15	// InstallPackage downloads the source release tarball and copies declared install mappings.
16	// It records installed files in the returned InstalledEntry.
17	func InstallPackage(pkg *Package) (InstalledEntry, error) {
18		entry := InstalledEntry{
19			Name:        pkg.Name,
20			Version:     pkg.Version,
21			Type:        pkg.Type,
22			Source:      pkg.Source,
23			InstalledAt: time.Now(),
24		}
25	
26		// Download and extract the release tarball to a temp directory.
27		tmpDir, err := os.MkdirTemp("", "ddx-install-"+pkg.Name+"-*")
28		if err != nil {
29			return entry, fmt.Errorf("creating temp dir: %w", err)
30		}
31		defer func() { _ = os.RemoveAll(tmpDir) }()
32	
33		tarballURL := githubTarballURL(pkg.Source, pkg.Version)
34		extractedDir, err := downloadAndExtract(tarballURL, tmpDir)
35		if err != nil {
36			return entry, fmt.Errorf("downloading %s: %w", tarballURL, err)
37		}
38	
39		if manifestPkg, manifestMissing, manifestIssues, manifestErr := LoadPackageManifestWithFallback(extractedDir, pkg); manifestErr == nil || (os.IsNotExist(manifestErr) && manifestMissing) {
40			if manifestPkg != nil {
41				pkg = manifestPkg
42			}
43		} else {
44			if len(manifestIssues) > 0 {
45				return entry, fmt.Errorf("validating package manifest: %s", JoinValidationIssues(manifestIssues))
46			}
47			return entry, fmt.Errorf("loading package manifest: %w", manifestErr)
48		}
49	
50		if pkg.Install.Root == nil {
51			pkg.Install.Root = &InstallMapping{
52				Source: ".",
53				Target: defaultPackageRootTarget(pkg.Name),
54			}
55		}
56	
57		if issues := ValidatePackageStructure(extractedDir, pkg); len(issues) > 0 {
58			return entry, fmt.Errorf("validating package structure: %s", JoinValidationIssues(issues))
59		}
60	
61		// Process Root mapping first - copy the entire plugin to central location.
62		var installedRoot string
63		if pkg.Install.Root != nil {
64			files, err := copyMapping(extractedDir, pkg.Install.Root)
65			if err != nil {
66				return entry, fmt.Errorf("installing plugin root: %w", err)
67			}
68			entry.Files = append(entry.Files, files...)
69			installedRoot = ExpandHome(pkg.Install.Root.Target)
70	
71			// Ensure declared executables have the execute bit set.
72			for _, rel := range pkg.Install.Executable {
73				p := filepath.Join(installedRoot, filepath.FromSlash(rel))
74				if info, err := os.Stat(p); err == nil && !info.IsDir() {
75					_ = os.Chmod(p, info.Mode()|0111)
76				}
77			}
78		}
79	
80		// Create project-local symlink to global plugin root so that project-relative
81		// paths (e.g. .ddx/plugins/helix/workflows/) resolve correctly.
82		// Only when the root target is a global (~/...) path — skip for project-local targets.
83		if installedRoot != "" && pkg.Install.Root != nil && strings.HasPrefix(pkg.Install.Root.Target, "~") {
84			localPluginDir := filepath.Join(".ddx", "plugins", pkg.Name)
85			if err := os.MkdirAll(filepath.Dir(localPluginDir), 0755); err == nil {
86				// Remove existing file/symlink/directory.
87				if _, err := os.Lstat(localPluginDir); err == nil {
88					_ = os.RemoveAll(localPluginDir)
89				}
90				_ = os.Symlink(installedRoot, localPluginDir)
91			}
92		}
93	
94		// Process Skills mappings — symlink from installed root when available,
95		// otherwise fall back to copying from the extracted tarball.
96		for i := range pkg.Install.Skills {
97			skill := &pkg.Install.Skills[i]
98			if installedRoot != "" {
99				files, err := symlinkSkills(installedRoot, skill)
100				if err != nil {
101					return entry, fmt.Errorf("symlinking skills: %w", err)
102				}
103				entry.Files = append(entry.Files, files...)
104			} else {
105				files, err := copyMapping(extractedDir, skill)
106				if err != nil {
107					return entry, fmt.Errorf("installing skills: %w", err)
108				}
109				entry.Files = append(entry.Files, files...)
110			}
111		}
112	
113		// Process Scripts mapping — copy the script to the target path.
114		// If the target is already a symlink, the developer is managing it
115		// themselves (e.g. symlink to their git checkout) — skip with a notice.
116		if pkg.Install.Scripts != nil {
117			dst := ExpandHome(pkg.Install.Scripts.Target)
118			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
119				target, _ := os.Readlink(dst)
120				fmt.Fprintf(os.Stderr, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
121				entry.Files = append(entry.Files, dst)
122			} else {
123				srcDir := extractedDir
124				if installedRoot != "" {
125					srcDir = installedRoot
126				}
127				files, err := copyMapping(srcDir, pkg.Install.Scripts)
128				if err != nil {
129					return entry, fmt.Errorf("installing scripts: %w", err)
130				}
131				entry.Files = append(entry.Files, files...)
132	
133				// Ensure the installed script is executable.
134				if info, err := os.Stat(dst); err == nil && !info.IsDir() {
135					_ = os.Chmod(dst, info.Mode()|0111)
136				}
137			}
138		}
139	
140		// Process symlinks.
141		for _, sym := range pkg.Install.Symlinks {
142			src := ExpandHome(sym.Source)
143			dst := ExpandHome(sym.Target)
144	
145			// Create parent dir if needed.
146			if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
147				return entry, fmt.Errorf("creating symlink dir %s: %w", filepath.Dir(dst), err)
148			}
149	
150			// Remove existing symlink/file if present.
151			if _, err := os.Lstat(dst); err == nil {
152				if err := os.RemoveAll(dst); err != nil {
153					return entry, fmt.Errorf("removing existing %s: %w", dst, err)
154				}
155			}
156	
157			if err := os.Symlink(src, dst); err != nil {
158				return entry, fmt.Errorf("creating symlink %s -> %s: %w", dst, src, err)
159			}
160			entry.Files = append(entry.Files, dst)
161		}
162	
163		return entry, nil
164	}
