166	// InstallResource installs a single resource file (e.g. "persona/strict-code-reviewer")
167	// from the ddx-library GitHub repo into the local .ddx/plugins/ddx/<type>/ directory.
168	func InstallResource(resourcePath string) (InstalledEntry, error) {
169		entry := InstalledEntry{
170			Name:        resourcePath,
171			Version:     "latest",
172			Type:        PackageTypeResource,
173			Source:      "https://github.com/DocumentDrivenDX/ddx-library",
174			InstalledAt: time.Now(),
175		}
176	
177		// resourcePath is like "persona/strict-code-reviewer"
178		parts := strings.SplitN(resourcePath, "/", 2)
179		if len(parts) != 2 {
180			return entry, fmt.Errorf("invalid resource path %q: expected <type>/<name>", resourcePath)
181		}
182		resourceType, resourceName := parts[0], parts[1]
183	
184		// Determine target directory relative to cwd.
185		target := filepath.Join(".ddx", "plugins", "ddx", resourceType+"s")
186		if err := os.MkdirAll(target, 0755); err != nil {
187			return entry, fmt.Errorf("creating target directory %s: %w", target, err)
188		}
189	
190		// Fetch raw file from GitHub.
191		rawURL := fmt.Sprintf(
192			"https://raw.githubusercontent.com/easel/ddx-library/main/%ss/%s.md",
193			resourceType, resourceName,
194		)
195	
196		destFile := filepath.Join(target, resourceName+".md")
197		if err := downloadFile(rawURL, destFile); err != nil {
198			return entry, fmt.Errorf("downloading %s: %w", rawURL, err)
199		}
200	
201		entry.Files = append(entry.Files, destFile)
202		return entry, nil
203	}
