205	// UninstallPackage removes files recorded in the entry.
206	func UninstallPackage(entry *InstalledEntry) error {
207		var errs []string
208		for _, f := range entry.Files {
209			expanded := ExpandHome(f)
210			if err := os.Remove(expanded); err != nil && !os.IsNotExist(err) {
211				errs = append(errs, fmt.Sprintf("removing %s: %v", f, err))
212			}
213		}
214		if len(errs) > 0 {
215			return fmt.Errorf("uninstall errors: %s", strings.Join(errs, "; "))
216		}
217		return nil
218	}
