220	// githubTarballURL builds a GitHub release tarball URL from a repo URL and version tag.
221	// e.g. "https://github.com/owner/repo" + "1.0.0" →
222	//
223	//	"https://github.com/owner/repo/archive/refs/tags/v1.0.0.tar.gz"
224	func githubTarballURL(repoURL, version string) string {
225		tag := version
226		if !strings.HasPrefix(tag, "v") {
227			tag = "v" + tag
228		}
229		return strings.TrimRight(repoURL, "/") + "/archive/refs/tags/" + tag + ".tar.gz"
230	}
