232	// downloadAndExtract downloads a .tar.gz from url into destDir and returns
233	// the path of the single top-level directory extracted from the archive.
234	func downloadAndExtract(url, destDir string) (string, error) {
235		resp, err := http.Get(url) //nolint:noctx
236		if err != nil {
237			return "", fmt.Errorf("fetching %s: %w", url, err)
238		}
239		defer func() { _ = resp.Body.Close() }()
240	
241		if resp.StatusCode != http.StatusOK {
242			return "", fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
243		}
244	
245		gz, err := gzip.NewReader(resp.Body)
246		if err != nil {
247			return "", fmt.Errorf("reading gzip: %w", err)
248		}
249		defer func() { _ = gz.Close() }()
250	
251		tr := tar.NewReader(gz)
252		var topDir string
253	
254		for {
255			hdr, err := tr.Next()
256			if err == io.EOF {
257				break
258			}
259			if err != nil {
260				return "", fmt.Errorf("reading tar: %w", err)
261			}
262	
263			// Sanitize path to prevent directory traversal.
264			clean := filepath.Clean(hdr.Name)
265			if strings.HasPrefix(clean, "..") {
266				continue
267			}
268	
269			dest := filepath.Join(destDir, clean)
270	
271			// Skip PAX global headers (GitHub tarballs include these).
272			if hdr.Typeflag == tar.TypeXGlobalHeader {
273				continue
274			}
275	
276			// Track the top-level directory name.
277			parts := strings.SplitN(clean, string(filepath.Separator), 2)
278			if topDir == "" && parts[0] != "" && parts[0] != "." {
279				topDir = parts[0]
280			}
281	
282			switch hdr.Typeflag {
283			case tar.TypeDir:
284				if err := os.MkdirAll(dest, 0755); err != nil {
285					return "", err
286				}
287			case tar.TypeReg:
288				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
289					return "", err
290				}
291				f, err := os.OpenFile(dest, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, hdr.FileInfo().Mode())
292				if err != nil {
293					return "", err
294				}
295				if _, err := io.Copy(f, tr); err != nil {
296					_ = f.Close()
297					return "", err
298				}
299				_ = f.Close()
300			case tar.TypeSymlink:
301				if err := os.MkdirAll(filepath.Dir(dest), 0755); err != nil {
302					return "", err
303				}
304				_ = os.Remove(dest)
305				if err := os.Symlink(hdr.Linkname, dest); err != nil {
306					return "", err
307				}
308			}
309		}
310	
311		if topDir == "" {
312			return destDir, nil
313		}
314		return filepath.Join(destDir, topDir), nil
315	}
