317	// symlinkSkills creates symlinks in the target skill directory pointing to the
318	// corresponding entries in the installed plugin root. This keeps skills in sync
319	// with the plugin rather than creating independent copies.
320	//
321	// The source entries may themselves be symlinks (e.g. HELIX's
322	// .agents/skills/helix-align -> ../../skills/helix-align). We resolve through
323	// all symlinks using filepath.EvalSymlinks so the output symlinks point to
324	// real directories, not to intermediate symlinks that may contain stale or
325	// Docker-only paths.
326	func symlinkSkills(installedRoot string, skill *InstallMapping) ([]string, error) {
327		srcDir := filepath.Join(installedRoot, filepath.FromSlash(skill.Source))
328		dstDir := ExpandHome(skill.Target)
329		cleanSource := filepath.Clean(filepath.FromSlash(skill.Source))
330	
331		entries, err := os.ReadDir(srcDir)
332		if os.IsNotExist(err) {
333			return nil, nil
334		}
335		if err != nil {
336			return nil, fmt.Errorf("reading skills dir %s: %w", srcDir, err)
337		}
338		if len(entries) == 0 && (cleanSource == filepath.Join(".agents", "skills") || cleanSource == filepath.Join(".claude", "skills")) {
339			fallbackDir := filepath.Join(installedRoot, "skills")
340			fallbackEntries, fallbackErr := os.ReadDir(fallbackDir)
341			if fallbackErr == nil {
342				srcDir = fallbackDir
343				entries = fallbackEntries
344			}
345		}
346	
347		if err := os.MkdirAll(dstDir, 0755); err != nil {
348			return nil, fmt.Errorf("creating skills dir %s: %w", dstDir, err)
349		}
350	
351		allowed := make(map[string]bool, len(entries))
352		for _, e := range entries {
353			allowed[e.Name()] = true
354		}
355		if err := pruneStaleSkillLinks(installedRoot, dstDir, allowed); err != nil {
356			return nil, err
357		}
358	
359		var written []string
360		for _, e := range entries {
361			src := filepath.Join(srcDir, e.Name())
362			dst := filepath.Join(dstDir, e.Name())
363	
364			// Compute link target from the LOGICAL src path, NOT from the
365			// EvalSymlinks-resolved real path on disk (ddx-6365b2b3).
366			// Resolving real path follows indirections like
367			// <project>/.ddx/plugins/helix → ~/.ddx/plugins/helix, then
368			// filepath.Rel produces a repo-escaping link like
369			// ../../../../../../home/erik/.ddx/plugins/helix/.agents/skills/X
370			// which gets committed and re-rewritten to each machine's $HOME.
371			// Using the logical src keeps the link inside the project /
372			// inside the package's logical layout regardless of where the
373			// plugin physically lives.
374			logicalSrc := src
375	
376			// Verify the source actually resolves to a directory. os.Stat
377			// follows symlinks for this check; we only use it to gate
378			// existence + recover broken tarball links, never to mutate
379			// linkTarget.
380			if info, statErr := os.Stat(logicalSrc); statErr != nil || !info.IsDir() {
381				// Tarball-build recovery: GitHub's archive tool sometimes
382				// bakes absolute paths from the build machine into symlink
383				// targets (e.g. /home/user/Projects/helix/skills/X), which
384				// break on every other machine. Fall back to looking up the
385				// entry by basename under installedRoot/skills/ (the canonical
386				// storage location for plugin skills).
387				candidate := filepath.Join(installedRoot, "skills", e.Name())
388				if cInfo, cErr := os.Stat(candidate); cErr == nil && cInfo.IsDir() {
389					logicalSrc = candidate
390				} else {
391					// Truly broken — skip this entry.
392					continue
393				}
394			}
395	
396			// Remove existing file/symlink/directory at dst.
397			if _, err := os.Lstat(dst); err == nil {
398				if err := os.RemoveAll(dst); err != nil {
399					return nil, fmt.Errorf("removing existing %s: %w", dst, err)
400				}
401			}
402	
403			// FEAT-015 §5 "Relative Symlinks for Plugins" — compute a
404			// path-relative target so the link survives clones, home-
405			// directory moves, and tarball rebuilds on a different machine.
406			// Fall back to the absolute path only when filepath.Rel refuses
407			// (different filesystem roots; extremely rare on Linux/macOS).
408			linkTarget := logicalSrc
409			absDstDir, dstAbsErr := filepath.Abs(filepath.Dir(dst))
410			absSrc, srcAbsErr := filepath.Abs(logicalSrc)
411			if dstAbsErr == nil && srcAbsErr == nil {
412				if rel, relErr := filepath.Rel(absDstDir, absSrc); relErr == nil {
413					linkTarget = rel
414				}
415			}
416	
417			if err := os.Symlink(linkTarget, dst); err != nil {
418				return nil, fmt.Errorf("symlinking %s -> %s: %w", dst, linkTarget, err)
419			}
420			written = append(written, dst)
421		}
422		return written, nil
423	}
