425	func pruneStaleSkillLinks(installedRoot, dstDir string, allowed map[string]bool) error {
426		if installedRoot == "" {
427			return nil
428		}
429	
430		entries, err := os.ReadDir(dstDir)
431		if os.IsNotExist(err) {
432			return nil
433		}
434		if err != nil {
435			return fmt.Errorf("reading skills dir %s: %w", dstDir, err)
436		}
437	
438		absRoot, err := filepath.Abs(installedRoot)
439		if err != nil {
440			absRoot = installedRoot
441		}
442	
443		for _, e := range entries {
444			name := e.Name()
445			if allowed[name] {
446				continue
447			}
448	
449			dstPath := filepath.Join(dstDir, name)
450			info, err := os.Lstat(dstPath)
451			if err != nil {
452				continue
453			}
454			if info.Mode()&os.ModeSymlink == 0 {
455				continue
456			}
457	
458			target, err := resolveSymlinkTarget(dstPath)
459			if err != nil {
460				continue
461			}
462			if !isWithinRoot(target, absRoot) {
463				continue
464			}
465	
466			if err := os.RemoveAll(dstPath); err != nil {
467				return fmt.Errorf("removing stale skill link %s: %w", dstPath, err)
468			}
469		}
470		return nil
471	}
472	
473	func resolveSymlinkTarget(path string) (string, error) {
474		target, err := filepath.EvalSymlinks(path)
475		if err == nil {
476			if abs, absErr := filepath.Abs(target); absErr == nil {
477				return abs, nil
478			}
479			return target, nil
480		}
481	
482		linkTarget, readErr := os.Readlink(path)
483		if readErr != nil {
484			return "", err
485		}
486	
487		if !filepath.IsAbs(linkTarget) {
488			linkTarget = filepath.Join(filepath.Dir(path), linkTarget)
489		}
490		linkTarget = filepath.Clean(linkTarget)
491		if abs, absErr := filepath.Abs(linkTarget); absErr == nil {
492			linkTarget = abs
493		}
494		return linkTarget, nil
495	}
496	
497	func isWithinRoot(target, root string) bool {
498		if root == "" || target == "" {
499			return false
500		}
501		rel, err := filepath.Rel(root, target)
502		if err != nil {
503			return false
504		}
505		if rel == "." {
506			return true
507		}
508		if rel == ".." {
509			return false
510		}
511		return !strings.HasPrefix(rel, ".."+string(filepath.Separator))
512	}
