514	// SymlinkSkillsFromRoot creates skill symlinks from an installed plugin root.
515	// Exported for use by local install path.
516	func SymlinkSkillsFromRoot(installedRoot string, skill *InstallMapping) ([]string, error) {
517		return symlinkSkills(installedRoot, skill)
518	}
