520	// CopyScriptFromRoot copies a script from an installed plugin root to the
521	// target path. Exported for use by local install path.
522	func CopyScriptFromRoot(installedRoot string, mapping *InstallMapping) (string, error) {
523		files, err := copyMapping(installedRoot, mapping)
524		if err != nil {
525			return "", err
526		}
527		// Ensure executable.
528		dst := ExpandHome(mapping.Target)
529		if info, err := os.Stat(dst); err == nil && !info.IsDir() {
530			_ = os.Chmod(dst, info.Mode()|0111)
531		}
532		if len(files) > 0 {
533			return files[0], nil
534		}
535		return dst, nil
536	}
