538	// copyMapping copies files from srcDir/<mapping.Source> to ExpandHome(mapping.Target).
539	// If the source is a single file and the target does not end with a path
540	// separator, the target is treated as the exact destination file path.
541	// If the source is a directory (or target ends with /), files are copied
542	// into the target directory.
543	// Returns the list of destination files written.
544	func copyMapping(srcDir string, mapping *InstallMapping) ([]string, error) {
545		src := filepath.Join(srcDir, filepath.FromSlash(mapping.Source))
546		dst := ExpandHome(mapping.Target)
547	
548		info, err := os.Stat(src)
549		if os.IsNotExist(err) {
550			// Source path doesn't exist in this repo — skip silently.
551			return nil, nil
552		}
553		if err != nil {
554			return nil, err
555		}
556	
557		var written []string
558	
559		if info.IsDir() {
560			// If dst is an existing symlink (e.g. from a prior --local install),
561			// remove it before creating the real directory.
562			if li, err := os.Lstat(dst); err == nil && li.Mode()&os.ModeSymlink != 0 {
563				if err := os.Remove(dst); err != nil {
564					return nil, fmt.Errorf("removing symlink at %s: %w", dst, err)
565				}
566			}
567	
568			// Copy directory tree into dst (create dst as a directory).
569			if err := os.MkdirAll(dst, 0755); err != nil {
570				return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
571			}
572	
573			// HELIX skills use symlinks, so resolve each entry via os.Stat.
574			entries, err := os.ReadDir(src)
575			if err != nil {
576				return nil, err
577			}
578			for _, e := range entries {
579				srcPath := filepath.Join(src, e.Name())
580				dstPath := filepath.Join(dst, e.Name())
581	
582				fi, err := os.Stat(srcPath)
583				if err != nil {
584					continue // skip broken symlinks
585				}
586	
587				if fi.IsDir() {
588					subFiles, subErr := copyMapping(srcPath, &InstallMapping{Source: ".", Target: dstPath})
589					if subErr != nil {
590						return nil, subErr
591					}
592					written = append(written, subFiles...)
593				} else if fi.Mode().IsRegular() {
594					if err := copyFile(srcPath, dstPath); err != nil {
595						return nil, err
596					}
597					written = append(written, dstPath)
598				}
599			}
600		} else {
601			// Source is a single file. If target ends with /, copy into that
602			// directory using the source filename; otherwise treat target as
603			// the exact destination file path.
604			var dstFile string
605			if strings.HasSuffix(mapping.Target, "/") {
606				if err := os.MkdirAll(dst, 0755); err != nil {
607					return nil, fmt.Errorf("creating target dir %s: %w", dst, err)
608				}
609				dstFile = filepath.Join(dst, filepath.Base(src))
610			} else {
611				dstFile = dst
612			}
613			if err := copyFile(src, dstFile); err != nil {
614				return nil, err
615			}
616			written = append(written, dstFile)
617		}
618	
619		return written, nil
620	}
621	
622	// copyFile copies src to dst, creating parent directories as needed.
623	// Preserves the source file's permissions. If dst already exists (file,
624	// symlink, or directory), it is removed first.
625	func copyFile(src, dst string) error {
626		if err := os.MkdirAll(filepath.Dir(dst), 0755); err != nil {
627			return err
628		}
629	
630		// Remove any existing file/symlink/directory at dst.
631		if _, err := os.Lstat(dst); err == nil {
632			if err := os.RemoveAll(dst); err != nil {
633				return fmt.Errorf("removing existing %s: %w", dst, err)
634			}
635		}
636	
637		srcInfo, err := os.Stat(src)
638		if err != nil {
639			return err
640		}
641	
642		in, err := os.Open(src)
643		if err != nil {
644			return err
645		}
646		defer func() { _ = in.Close() }()
647	
648		out, err := os.OpenFile(dst, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, srcInfo.Mode())
649		if err != nil {
650			return err
651		}
652		defer func() { _ = out.Close() }()
653	
654		_, err = io.Copy(out, in)
655		return err
656	}
657	
658	// downloadFile fetches url and writes it to dest.
659	func downloadFile(url, dest string) error {
660		resp, err := http.Get(url) //nolint:noctx
661		if err != nil {
662			return fmt.Errorf("fetching %s: %w", url, err)
663		}
664		defer func() { _ = resp.Body.Close() }()
665	
666		if resp.StatusCode != http.StatusOK {
667			return fmt.Errorf("fetching %s: HTTP %s", url, resp.Status)
668		}
669	
670		f, err := os.Create(dest)
671		if err != nil {
672			return err
673		}
674		defer func() { _ = f.Close() }()
675	
676		_, err = io.Copy(f, resp.Body)
677		return err
678	}
