680	// ExpandHome expands a leading ~ to the user's home directory.
681	func ExpandHome(path string) string {
682		if !strings.HasPrefix(path, "~") {
683			return path
684		}
685		home, err := os.UserHomeDir()
686		if err != nil {
687			return path
688		}
689		return filepath.Join(home, path[1:])
690	}
