20	// newInstallCommand creates the "ddx install <name>" command.
21	func (f *CommandFactory) newInstallCommand() *cobra.Command {
22		cmd := &cobra.Command{
23			Use:   "install [<name>]",
24			Short: "Install a package, resource, or the embedded DDx skills",
25			Long: `Install a package or resource from the DDx registry, or extract the
26	embedded DDx skill tree into the user's home with --global.
27	
28	Examples:
29	  ddx install helix                        # Install HELIX workflow
30	  ddx install helix --force                # Reinstall even if already up to date
31	  ddx install persona/strict-code-reviewer # Install a single persona
32	  ddx install --global                     # Extract embedded skills to ~/.ddx/ (FEAT-015 AC-002)
33	  ddx install --global --force             # Overwrite existing ~/.ddx/skills/ files`,
34			Args: func(cmd *cobra.Command, args []string) error {
35				if global, _ := cmd.Flags().GetBool("global"); global {
36					return cobra.MaximumNArgs(1)(cmd, args)
37				}
38				return cobra.ExactArgs(1)(cmd, args)
39			},
40			RunE: f.runInstall,
41		}
42		cmd.Flags().BoolP("force", "f", false, "Reinstall even if already at the latest version")
43		cmd.Flags().String("local", "", "Install from a local directory instead of the registry")
44		cmd.Flags().Bool("global", false, "Extract embedded DDx skills to ~/.ddx/ and link ~/.agents/, ~/.claude/")
45		return cmd
46	}
