48	func (f *CommandFactory) runInstall(cmd *cobra.Command, args []string) error {
49		out := cmd.OutOrStdout()
50		force, _ := cmd.Flags().GetBool("force")
51	
52		// Handle --global: extract embedded DDx skill tree into the user's
53		// home directory. Does not touch project-local state, so no cwd shuffle
54		// is required.
55		if global, _ := cmd.Flags().GetBool("global"); global {
56			return f.installGlobal(force, out)
57		}
58	
59		if len(args) == 0 {
60			return fmt.Errorf("install: a package name is required unless --global is set")
61		}
62		name := args[0]
63	
64		// Ensure install operations resolve relative paths against the project
65		// root (WorkingDir), not the caller's cwd. This prevents creating stale
66		// .ddx/ workspaces in subdirectories.
67		if f.WorkingDir != "" {
68			origDir, _ := os.Getwd()
69			if origDir != f.WorkingDir {
70				if err := os.Chdir(f.WorkingDir); err == nil {
71					defer func() { _ = os.Chdir(origDir) }()
72				}
73			}
74		}
75	
76		// Handle --local: install from a local directory instead of registry.
77		if localPath, _ := cmd.Flags().GetString("local"); localPath != "" {
78			return f.installLocal(name, localPath, force, out)
79		}
80	
81		if registry.IsResourcePath(name) {
82			// Individual resource install (e.g. "persona/strict-code-reviewer")
83			fmt.Fprintf(out, "Installing resource %s...\n", name)
84			entry, err := registry.InstallResource(name)
85			if err != nil {
86				return fmt.Errorf("install resource: %w", err)
87			}
88	
89			state, err := registry.LoadState()
90			if err != nil {
91				return fmt.Errorf("loading state: %w", err)
92			}
93			state.AddOrUpdate(entry)
94			if err := registry.SaveState(state); err != nil {
95				return fmt.Errorf("saving state: %w", err)
96			}
97	
98			fmt.Fprintf(out, "Installed %s\n", name)
99			return nil
100		}
101	
102		// Package install (e.g. "helix")
103		reg := registry.BuiltinRegistry()
104		pkg, err := reg.Find(name)
105		if err != nil {
106			return err
107		}
108	
109		// Fetch actual latest version from GitHub (overrides hardcoded registry version).
110		if release, err := update.FetchLatestReleaseForRepo(pkg.Source); err == nil {
111			pkg.Version = strings.TrimPrefix(release.TagName, "v")
112		}
113	
114		// Check if already installed at the latest version.
115		state, err := registry.LoadState()
116		if err == nil {
117			for _, e := range state.Installed {
118				if e.Name == name {
119					if e.Version == pkg.Version {
120						if !force {
121							fmt.Fprintf(out, "%s %s is already up to date\n", e.Name, e.Version)
122							return nil
123						}
124						fmt.Fprintf(out, "Reinstalling %s %s...\n", e.Name, e.Version)
125					} else {
126						fmt.Fprintf(out, "Updating %s from %s to %s...\n", e.Name, e.Version, pkg.Version)
127					}
128				}
129			}
130		}
131	
132		// Capture old file list before installing so we can remove stale files.
133		var oldFiles []string
134		if state != nil {
135			if old := state.FindInstalled(name); old != nil {
136				oldFiles = append([]string{}, old.Files...)
137			}
138		}
139	
140		fmt.Fprintf(out, "Installing %s %s from %s...\n", pkg.Name, pkg.Version, pkg.Source)
141	
142		entry, err := registry.InstallPackage(pkg)
143		if err != nil {
144			return fmt.Errorf("install package: %w", err)
145		}
146	
147		removed := removeStaleFilesFromInstall(oldFiles, entry.Files)
148		if removed > 0 {
149			fmt.Fprintf(out, "Removed %d stale file(s)\n", removed)
150		}
151	
152		state, stateErr := registry.LoadState()
153		if stateErr != nil {
154			return fmt.Errorf("loading state: %w", stateErr)
155		}
156		state.AddOrUpdate(entry)
157		if err := registry.SaveState(state); err != nil {
158			return fmt.Errorf("saving state: %w", err)
159		}
160	
161		fmt.Fprintf(out, "Installed %s %s (%d file(s))\n", pkg.Name, pkg.Version, len(entry.Files))
162	
163		// Auto-commit skill symlinks and other trackable changes.
164		commitPluginChanges(name, pkg.Version)
165	
166		return nil
167	}
168	
169	func removeStaleFilesFromInstall(oldFiles []string, newFiles []string) int {
170		if len(oldFiles) == 0 {
171			return 0
172		}
173	
174		newSet := make(map[string]bool, len(newFiles))
175		for _, f := range newFiles {
176			newSet[f] = true
177		}
178	
179		removed := 0
180		for _, f := range oldFiles {
181			if newSet[f] {
182				continue
183			}
184			expanded := registry.ExpandHome(f)
185			if err := os.RemoveAll(expanded); err == nil {
186				removed++
187			}
188		}
189		return removed
190	}
