192	// commitPluginChanges stages and commits plugin-related changes in the working tree.
193	// Non-fatal: if git operations fail (not a repo, nothing to commit), it's silently skipped.
194	func commitPluginChanges(name, version string) {
195		// Stage skill symlinks and any other trackable plugin artifacts.
196		paths := []string{".agents/skills/", ".claude/skills/"}
197		ctx := context.Background()
198		for _, p := range paths {
199			if _, err := os.Stat(p); err == nil {
200				gitAdd := internalgit.Command(ctx, "", "add", p)
201				_ = gitAdd.Run()
202			}
203		}
204	
205		// Check if there's anything to commit.
206		status := internalgit.Command(ctx, "", "diff", "--cached", "--quiet")
207		if status.Run() == nil {
208			return // nothing staged
209		}
210	
211		msg := fmt.Sprintf("chore: install %s %s", name, version)
212		gitCommit := internalgit.Command(ctx, "", "commit", "-m", msg)
213		_ = gitCommit.Run()
214	}
