216	func prepareSymlinkTarget(target string, force bool) error {
217		if info, err := os.Lstat(target); err == nil {
218			if info.Mode()&os.ModeSymlink != 0 || force {
219				if err := os.RemoveAll(target); err != nil {
220					return fmt.Errorf("removing existing %s: %w", target, err)
221				}
222				return nil
223			}
224			return fmt.Errorf("%s already exists (use --force to replace)", target)
225		} else if !os.IsNotExist(err) {
226			return fmt.Errorf("checking existing %s: %w", target, err)
227		}
228		return nil
229	}
