231	// installLocal installs a plugin from a local directory. It creates the
232	// declared plugin root symlink, then discovers and symlinks skills the same
233	// way a registry install does.
234	func (f *CommandFactory) installLocal(name, localPath string, force bool, out io.Writer) error {
235		// Resolve to absolute path.
236		absPath, err := filepath.Abs(localPath)
237		if err != nil {
238			return fmt.Errorf("resolving path %s: %w", localPath, err)
239		}
240		if _, err := os.Stat(absPath); os.IsNotExist(err) {
241			return fmt.Errorf("local path does not exist: %s", absPath)
242		}
243	
244		// Load package.yaml when present so local installs honor the manifest
245		// contract, but keep the built-in registry as a compatibility fallback.
246		reg := registry.BuiltinRegistry()
247		fallbackPkg, _ := reg.Find(name)
248	
249		pkg, manifestMissing, manifestIssues, manifestErr := registry.LoadPackageManifestWithFallback(absPath, fallbackPkg)
250		if manifestErr == nil {
251			if strings.TrimSpace(pkg.Name) != "" && pkg.Name != name {
252				return fmt.Errorf("local package name %q does not match package.yaml name %q", name, pkg.Name)
253			}
254		} else {
255			if os.IsNotExist(manifestErr) && manifestMissing {
256				if pkg == nil {
257					pkg = &registry.Package{
258						Name:        name,
259						Version:     "local",
260						Description: "local plugin package",
261						Type:        registry.PackageTypePlugin,
262						Source:      absPath,
263					}
264				}
265			} else if len(manifestIssues) > 0 {
266				return fmt.Errorf("validating package manifest: %w", manifestErr)
267			} else {
268				return fmt.Errorf("loading package manifest: %w", manifestErr)
269			}
270		}
271	
272		if pkg == nil {
273			pkg = &registry.Package{
274				Name:        name,
275				Version:     "local",
276				Description: "local plugin package",
277				Type:        registry.PackageTypePlugin,
278				Source:      absPath,
279			}
280		}
281	
282		if pkg.Install.Root == nil {
283			pkg.Install.Root = &registry.InstallMapping{
284				Source: ".",
285				Target: fmt.Sprintf(".ddx/plugins/%s", pkg.Name),
286			}
287		}
288	
289		if issues := registry.ValidatePackageStructure(absPath, pkg); len(issues) > 0 {
290			return fmt.Errorf("validating package structure: %s", registry.JoinValidationIssues(issues))
291		}
292	
293		pluginDir := registry.ExpandHome(pkg.Install.Root.Target)
294		var projectPluginDir string
295		if strings.HasPrefix(pkg.Install.Root.Target, "~") {
296			projectPluginDir = filepath.Join(".ddx", "plugins", pkg.Name)
297		}
298	
299		if err := prepareSymlinkTarget(pluginDir, force); err != nil {
300			return err
301		}
302		if projectPluginDir != "" {
303			if err := prepareSymlinkTarget(projectPluginDir, force); err != nil {
304				return err
305			}
306		}
307	
308		// Create the declared plugin root.
309		if err := os.MkdirAll(filepath.Dir(pluginDir), 0755); err != nil {
310			return fmt.Errorf("creating plugins dir: %w", err)
311		}
312		if projectPluginDir != "" {
313			if err := os.MkdirAll(filepath.Dir(projectPluginDir), 0755); err != nil {
314				return fmt.Errorf("creating project plugin dir: %w", err)
315			}
316		}
317	
318		// Create symlink to local path.
319		if err := os.Symlink(absPath, pluginDir); err != nil {
320			return fmt.Errorf("creating symlink %s -> %s: %w", pluginDir, absPath, err)
321		}
322	
323		fmt.Fprintf(out, "Linked %s -> %s\n", pluginDir, absPath)
324	
325		entry := registry.InstalledEntry{
326			Name:    pkg.Name,
327			Version: pkg.Version,
328			Type:    pkg.Type,
329			Source:  absPath,
330		}
331		entry.Files = append(entry.Files, pkg.Install.Root.Target)
332	
333		if projectPluginDir != "" {
334			if err := os.Symlink(pluginDir, projectPluginDir); err != nil {
335				return fmt.Errorf("creating project symlink %s -> %s: %w", projectPluginDir, pluginDir, err)
336			}
337			entry.Files = append(entry.Files, projectPluginDir)
338		}
339	
340		// Discover and symlink skills using the same logic as registry install.
341		for i := range pkg.Install.Skills {
342			skill := &pkg.Install.Skills[i]
343			files, err := registry.SymlinkSkillsFromRoot(absPath, skill)
344			if err != nil {
345				fmt.Fprintf(out, "Warning: skill symlink error: %v\n", err)
346				continue
347			}
348			entry.Files = append(entry.Files, files...)
349		}
350	
351		// Copy CLI script if defined (skip if target is a developer symlink).
352		if pkg.Install.Scripts != nil {
353			dst := registry.ExpandHome(pkg.Install.Scripts.Target)
354			if li, lErr := os.Lstat(dst); lErr == nil && li.Mode()&os.ModeSymlink != 0 {
355				target, _ := os.Readlink(dst)
356				fmt.Fprintf(out, "notice: %s is a symlink → %s (developer mode, skipping copy)\n", dst, target)
357				entry.Files = append(entry.Files, dst)
358			} else {
359				copied, err := registry.CopyScriptFromRoot(absPath, pkg.Install.Scripts)
360				if err != nil {
361					fmt.Fprintf(out, "Warning: script copy error: %v\n", err)
362				} else {
363					entry.Files = append(entry.Files, copied)
364				}
365			}
366		}
367	
368		// Set execute bits.
369		for _, rel := range pkg.Install.Executable {
370			p := filepath.Join(absPath, filepath.FromSlash(rel))
371			if info, err := os.Stat(p); err == nil && !info.IsDir() {
372				_ = os.Chmod(p, info.Mode()|0111)
373			}
374		}
375	
376		// Save install state.
377		state, _ := registry.LoadState()
378		if state == nil {
379			state = &registry.InstalledState{}
380		}
381		entry.InstalledAt = time.Now()
382		state.AddOrUpdate(entry)
383		if err := registry.SaveState(state); err != nil {
384			return fmt.Errorf("saving state: %w", err)
385		}
386	
387		fmt.Fprintf(out, "Installed %s (local) — %d file(s)\n", entry.Name, len(entry.Files))
388		commitPluginChanges(entry.Name, entry.Version)
389		return nil
390	}
