403	func (f *CommandFactory) runInstalled(cmd *cobra.Command, args []string) error {
404		out := cmd.OutOrStdout()
405	
406		state, err := registry.LoadState()
407		if err != nil {
408			return fmt.Errorf("loading state: %w", err)
409		}
410	
411		if len(state.Installed) == 0 {
412			fmt.Fprintln(out, "No packages installed.")
413			return nil
414		}
415	
416		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
417		fmt.Fprintln(w, "NAME\tVERSION\tTYPE\tSTATUS\tINSTALLED")
418		for _, e := range state.Installed {
419			status := "ok"
420			if !e.VerifyFiles() {
421				status = "BROKEN"
422			}
423			fmt.Fprintf(w, "%s\t%s\t%s\t%s\t%s\n",
424				e.Name,
425				e.Version,
426				string(e.Type),
427				status,
428				e.InstalledAt.Format("2006-01-02"),
429			)
430		}
431		return w.Flush()
432	}
