473	func (f *CommandFactory) newVerifyCommand() *cobra.Command {
474		return &cobra.Command{
475			Use:   "verify",
476			Short: "Verify installed package integrity",
477			Long:  `Check that all files recorded for installed packages still exist and symlinks resolve correctly.`,
478			Args:  cobra.NoArgs,
479			RunE:  f.runVerify,
480		}
481	}
482	
483	func (f *CommandFactory) runVerify(cmd *cobra.Command, args []string) error {
484		out := cmd.OutOrStdout()
485	
486		state, err := registry.LoadState()
487		if err != nil {
488			return fmt.Errorf("loading state: %w", err)
489		}
490	
491		if len(state.Installed) == 0 {
492			fmt.Fprintln(out, "No packages installed.")
493			return nil
494		}
495	
496		var totalIssues int
497		for _, entry := range state.Installed {
498			var issues []string
499			for _, f := range entry.Files {
500				expanded := registry.ExpandHome(f)
501				info, err := os.Lstat(expanded)
502				if os.IsNotExist(err) {
503					issues = append(issues, fmt.Sprintf("  missing: %s", f))
504					continue
505				}
506				if err != nil {
507					issues = append(issues, fmt.Sprintf("  error: %s: %v", f, err))
508					continue
509				}
510				// Check symlinks resolve.
511				if info.Mode()&os.ModeSymlink != 0 {
512					target, err := os.Readlink(expanded)
513					if err != nil {
514						issues = append(issues, fmt.Sprintf("  broken symlink: %s", f))
515						continue
516					}
517					// Resolve relative symlinks against their parent directory.
518					if !filepath.IsAbs(target) {
519						target = filepath.Join(filepath.Dir(expanded), target)
520					}
521					if _, err := os.Stat(target); os.IsNotExist(err) {
522						issues = append(issues, fmt.Sprintf("  broken symlink: %s -> %s", f, target))
523					}
524				}
525			}
526	
527			if len(issues) == 0 {
528				fmt.Fprintf(out, "%s %s: OK (%d files)\n", entry.Name, entry.Version, len(entry.Files))
529			} else {
530				fmt.Fprintf(out, "%s %s: %d issue(s)\n", entry.Name, entry.Version, len(issues))
531				for _, issue := range issues {
532					fmt.Fprintln(out, issue)
533				}
534				totalIssues += len(issues)
535			}
536		}
537	
538		if totalIssues > 0 {
539			return fmt.Errorf("%d integrity issue(s) found — run 'ddx install <name> --force' to repair", totalIssues)
540		}
541		return nil
