580	func (f *CommandFactory) newOutdatedCommand() *cobra.Command {
581		cmd := &cobra.Command{
582			Use:   "outdated",
583			Short: "List installed packages with available updates",
584			Long:  `Check installed packages against the registry and list those with newer versions available.`,
585			Args:  cobra.NoArgs,
586			RunE:  f.runOutdated,
587		}
