592	func (f *CommandFactory) runOutdated(cmd *cobra.Command, args []string) error {
593		out := cmd.OutOrStdout()
594		asJSON, _ := cmd.Flags().GetBool("json")
595	
596		state, err := registry.LoadState()
597		if err != nil {
598			return fmt.Errorf("reading installed state: %w", err)
599		}
600		if len(state.Installed) == 0 {
601			fmt.Fprintln(out, "No packages installed.")
602			return nil
603		}
604	
605		reg := registry.BuiltinRegistry()
606	
607		type outdatedEntry struct {
608			Name             string `json:"name"`
609			InstalledVersion string `json:"installed_version"`
610			LatestVersion    string `json:"latest_version"`
611		}
612	
613		var outdated []outdatedEntry
614		for _, entry := range state.Installed {
615			pkg, err := reg.Find(entry.Name)
616			if err != nil {
617				continue // not in registry, skip
618			}
619			if pkg.Version != entry.Version {
620				outdated = append(outdated, outdatedEntry{
621					Name:             entry.Name,
622					InstalledVersion: entry.Version,
623					LatestVersion:    pkg.Version,
624				})
625			}
626		}
627	
628		if len(outdated) == 0 {
629			fmt.Fprintln(out, "All installed packages are up to date.")
630			return nil
631		}
632	
633		if asJSON {
634			enc := json.NewEncoder(out)
635			enc.SetIndent("", "  ")
636			return enc.Encode(outdated)
637		}
638	
639		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
640		fmt.Fprintln(w, "NAME\tINSTALLED\tLATEST")
641		for _, o := range outdated {
642			fmt.Fprintf(w, "%s\t%s\t%s\n", o.Name, o.InstalledVersion, o.LatestVersion)
643		}
644		return w.Flush()
645	}
