3	import (
4		"errors"
5		"fmt"
6		"io/fs"
7		"os"
8		"path/filepath"
9		"strings"
10	)
11	
12	// Options controls Install behavior.
13	type Options struct {
14		// Force overwrites pre-existing real-file destinations. When false, existing
15		// real-file skill directories are preserved (per-skill skip). Pre-existing
16		// symlink destinations are ALWAYS removed regardless of Force.
17		Force bool
18	}
19	
20	// Install copies skills from src into <projectRoot>/.agents/skills/<name>/ and
21	// <projectRoot>/.claude/skills/<name>/ as real files. Never creates symlinks.
22	//
23	// Source layouts:
24	//   - Top-level skill dirs (embed.FS bootstrap): src has "<skillName>/..."
25	//   - Plugin layout (os.DirFS over plugin root): src has ".agents/skills/<skillName>";
26	//     when that path is a broken symlink (tarball authored with symlinks),
27	//     falls back to "skills/<skillName>".
28	func Install(src fs.FS, projectRoot string, opts Options) error {
29		if projectRoot == "" {
30			return errors.New("skills.Install: projectRoot is empty")
31		}
32	
33		skillNames, sources, err := discoverSkills(src)
34		if err != nil {
35			return fmt.Errorf("discover skills: %w", err)
36		}
37	
38		for _, name := range skillNames {
39			if err := validateSkillName(name); err != nil {
40				return err
41			}
42		}
43	
44		targets := []string{
45			filepath.Join(projectRoot, ".agents", "skills"),
46			filepath.Join(projectRoot, ".claude", "skills"),
47		}
48	
49		// Pre-flight: validate every destination resolves inside projectRoot.
50		// Done before any write so traversal/escape inputs error out cleanly.
51		absRoot, err := filepath.Abs(projectRoot)
52		if err != nil {
53			return fmt.Errorf("resolve projectRoot: %w", err)
54		}
55		for _, target := range targets {
56			for _, name := range skillNames {
57				destDir := filepath.Join(target, name)
58				if err := assertWithinRoot(destDir, absRoot); err != nil {
59					return err
60				}
61			}
62		}
63	
64		// Ensure target parents exist after validation.
65		for _, t := range targets {
66			if err := os.MkdirAll(t, 0o755); err != nil {
67				return fmt.Errorf("create %s: %w", t, err)
68			}
69			// Reject if target itself is a symlink escaping projectRoot.
70			if err := assertWithinRoot(t, absRoot); err != nil {
71				return err
72			}
73		}
74	
75		for i, name := range skillNames {
76			srcSub := sources[i]
77			for _, target := range targets {
78				destDir := filepath.Join(target, name)
79				info, lerr := os.Lstat(destDir)
80				if lerr == nil {
81					if info.Mode()&os.ModeSymlink != 0 {
82						// Symlink: always remove and replace, regardless of Force.
83						if err := os.Remove(destDir); err != nil {
84							return fmt.Errorf("remove pre-existing symlink %s: %w", destDir, err)
85						}
86					} else if !opts.Force {
87						// Real-file destination + !Force: skip per-skill (whole dir).
88						continue
89					} else {
90						// Real-file destination + Force: overwrite by removing first.
91						if err := os.RemoveAll(destDir); err != nil {
92							return fmt.Errorf("remove existing dir %s: %w", destDir, err)
93						}
94					}
95				}
96				if err := copyFromFS(srcSub, destDir); err != nil {
97					return fmt.Errorf("copy skill %q: %w", name, err)
98				}
99			}
100		}
101	
102		return nil
103	}
104	
105	// discoverSkills inspects src and returns parallel slices of skill names and
106	// per-skill sub-FSes rooted at the skill content. Handles both bootstrap
107	// (top-level) and plugin (.agents/skills) layouts.
108	func discoverSkills(src fs.FS) ([]string, []fs.FS, error) {
109		if info, err := fs.Stat(src, ".agents/skills"); err == nil && info.IsDir() {
110			entries, err := fs.ReadDir(src, ".agents/skills")
111			if err != nil {
112				return nil, nil, err
113			}
114			var names []string
115			var subs []fs.FS
116			for _, e := range entries {
117				name := e.Name()
118				primary := ".agents/skills/" + name
119				// Try the canonical path first. fs.Stat follows symlinks under os.DirFS,
120				// so a broken symlink yields an error here.
121				if _, statErr := fs.Stat(src, primary); statErr == nil {
122					sub, err := fs.Sub(src, primary)
123					if err != nil {
124						return nil, nil, err
125					}
126					names = append(names, name)
127					subs = append(subs, sub)
128					continue
129				}
130				// Broken symlink (tarball case) — fall back to skills/<name>.
131				fallback := "skills/" + name
132				if _, statErr := fs.Stat(src, fallback); statErr != nil {
133					continue
134				}
135				sub, err := fs.Sub(src, fallback)
136				if err != nil {
137					return nil, nil, err
138				}
139				names = append(names, name)
140				subs = append(subs, sub)
141			}
142			return names, subs, nil
143		}
144	
145		// Default layout: top-level entries are skill directories.
146		entries, err := fs.ReadDir(src, ".")
147		if err != nil {
148			return nil, nil, err
149		}
150		var names []string
151		var subs []fs.FS
152		for _, e := range entries {
153			if !e.IsDir() {
154				continue
155			}
156			sub, err := fs.Sub(src, e.Name())
157			if err != nil {
158				return nil, nil, err
159			}
160			names = append(names, e.Name())
161			subs = append(subs, sub)
162		}
163		return names, subs, nil
164	}
165	
166	// validateSkillName rejects names that could escape the destination tree.
167	func validateSkillName(name string) error {
168		if name == "" || name == "." || name == ".." {
169			return fmt.Errorf("skills.Install: invalid skill name %q", name)
170		}
171		if strings.ContainsAny(name, `/\`) {
172			return fmt.Errorf("skills.Install: skill name contains path separator: %q", name)
173		}
174		if filepath.IsAbs(name) {
175			return fmt.Errorf("skills.Install: skill name is absolute: %q", name)
176		}
177		if strings.Contains(name, "..") {
178			return fmt.Errorf("skills.Install: skill name contains parent reference: %q", name)
179		}
180		return nil
181	}
182	
183	// assertWithinRoot resolves dest (and the existing portion of its path) and
184	// returns an error if it escapes absRoot via symlinks or absolute paths.
185	func assertWithinRoot(dest, absRoot string) error {
186		abs, err := filepath.Abs(dest)
187		if err != nil {
188			return fmt.Errorf("resolve %s: %w", dest, err)
189		}
190		// Walk upward to find an existing ancestor and EvalSymlinks on it; this
191		// catches symlink-escapes even when the leaf does not yet exist.
192		check := abs
193		for {
194			if _, err := os.Lstat(check); err == nil {
195				resolved, err := filepath.EvalSymlinks(check)
196				if err != nil {
197					return fmt.Errorf("resolve symlinks for %s: %w", check, err)
198				}
199				resolvedRoot, rerr := filepath.EvalSymlinks(absRoot)
200				if rerr != nil {
201					// projectRoot may not exist yet — fall back to lexical compare.
202					resolvedRoot = absRoot
203				}
204				if !pathHasPrefix(resolved, resolvedRoot) {
205					return fmt.Errorf("skills.Install: path %s escapes project root %s", dest, absRoot)
206				}
207				break
208			}
209			parent := filepath.Dir(check)
210			if parent == check {
211				break
212			}
213			check = parent
214		}
215		if !pathHasPrefix(abs, absRoot) {
216			return fmt.Errorf("skills.Install: path %s escapes project root %s", dest, absRoot)
217		}
218		return nil
219	}
220	
221	func pathHasPrefix(p, prefix string) bool {
222		if p == prefix {
223			return true
224		}
225		sep := string(filepath.Separator)
226		if !strings.HasSuffix(prefix, sep) {
227			prefix += sep
228		}
229		return strings.HasPrefix(p, prefix)
230	}
231	
232	// copyFromFS recursively copies src (rooted at ".") into destDir as real files.
233	// Symlinks in the source are skipped (never materialized) — see FEAT-015
234	// "Cross-platform invariant".
235	func copyFromFS(src fs.FS, destDir string) error {
236		if err := os.MkdirAll(destDir, 0o755); err != nil {
237			return err
238		}
239		return fs.WalkDir(src, ".", func(p string, d fs.DirEntry, err error) error {
240			if err != nil {
241				return err
242			}
243			if p == "." {
244				return nil
245			}
246			if strings.Contains(p, "..") {
247				return fmt.Errorf("invalid path in source: %s", p)
248			}
249			target := filepath.Join(destDir, p)
250			if d.IsDir() {
251				return os.MkdirAll(target, 0o755)
252			}
253			if d.Type()&os.ModeSymlink != 0 {
254				// Skip plugin-source symlinks — never materialize.
255				return nil
256			}
257			data, rerr := fs.ReadFile(src, p)
258			if rerr != nil {
259				return rerr
260			}
261			return os.WriteFile(target, data, 0o644)
262		})
263	}
