9	
10		"github.com/DocumentDrivenDX/ddx/internal/skills"
11	)
12	
13	// installGlobal implements `ddx install --global`: extracts the embedded
14	// DDx skill tree into the user's home directory and chains relative
15	// symlinks from `~/.agents/skills/` and `~/.claude/skills/` so every
16	// skills-aware agent runtime sees the same canonical files in
17	// `~/.ddx/skills/`.
18	//
19	// Layout after success (per FEAT-015 AC-002):
20	//
21	//	~/.ddx/skills/<skill>/...            # real files
22	//	~/.agents/skills/<skill>  → ../../.ddx/skills/<skill>
23	//	~/.claude/skills/<skill>  → ../../.agents/skills/<skill>
24	//
25	// Idempotent: re-running updates files in place (force mirrors every
26	// existing file regardless of timestamp; without --force, existing files
27	// are left alone to respect user edits). Symlinks are always replaced to
28	// point at the new canonical target.
29	func (f *CommandFactory) installGlobal(force bool, out io.Writer) error {
30		home, err := os.UserHomeDir()
31		if err != nil {
32			return fmt.Errorf("install --global: resolve home directory: %w", err)
33		}
34	
35		ddxSkillsRoot := filepath.Join(home, ".ddx", "skills")
36		agentsSkillsRoot := filepath.Join(home, ".agents", "skills")
37		claudeSkillsRoot := filepath.Join(home, ".claude", "skills")
38	
39		// Enumerate top-level skill directories from the embedded tree. The
40		// embedded FS root contains one entry per skill (today just "ddx"),
41		// each with its own SKILL.md + reference/ layout.
42		topLevel, err := fs.ReadDir(skills.SkillFiles, ".")
43		if err != nil {
44			return fmt.Errorf("install --global: read embedded skill tree: %w", err)
45		}
46		var skillNames []string
47		for _, entry := range topLevel {
48			if entry.IsDir() {
49				skillNames = append(skillNames, entry.Name())
50			}
51		}
52		if len(skillNames) == 0 {
53			return fmt.Errorf("install --global: embedded skill tree is empty")
54		}
55	
56		// 1. Extract each skill into ~/.ddx/skills/<name>/.
57		if err := os.MkdirAll(ddxSkillsRoot, 0o755); err != nil {
58			return fmt.Errorf("install --global: create %s: %w", ddxSkillsRoot, err)
59		}
60		for _, name := range skillNames {
61			if err := extractSkillTree(skills.SkillFiles, name, filepath.Join(ddxSkillsRoot, name), force); err != nil {
62				return fmt.Errorf("install --global: extract %s: %w", name, err)
63			}
64		}
65	
66		// 2. Symlink from ~/.agents/skills/<name> → ../../.ddx/skills/<name>.
67		if err := os.MkdirAll(agentsSkillsRoot, 0o755); err != nil {
68			return fmt.Errorf("install --global: create %s: %w", agentsSkillsRoot, err)
69		}
70		for _, name := range skillNames {
71			target := filepath.Join("..", "..", ".ddx", "skills", name)
72			if err := replaceRelativeSymlink(filepath.Join(agentsSkillsRoot, name), target); err != nil {
73				return fmt.Errorf("install --global: symlink %s: %w", name, err)
74			}
75		}
76	
77		// 3. Symlink from ~/.claude/skills/<name> → ../../.agents/skills/<name>.
78		// Claude Code reads ~/.claude/skills/; chaining through ~/.agents/
79		// keeps one canonical anchor while every runtime finds the skill.
80		if err := os.MkdirAll(claudeSkillsRoot, 0o755); err != nil {
81			return fmt.Errorf("install --global: create %s: %w", claudeSkillsRoot, err)
82		}
83		for _, name := range skillNames {
84			target := filepath.Join("..", "..", ".agents", "skills", name)
85			if err := replaceRelativeSymlink(filepath.Join(claudeSkillsRoot, name), target); err != nil {
86				return fmt.Errorf("install --global: claude symlink %s: %w", name, err)
87			}
88		}
89	
90		fmt.Fprintf(out, "Extracted %d skill(s) to %s\n", len(skillNames), ddxSkillsRoot)
91		for _, name := range skillNames {
92			fmt.Fprintf(out, "  %s\n", name)
93		}
94		fmt.Fprintf(out, "Linked ~/.agents/skills and ~/.claude/skills to ~/.ddx/skills\n")
95		return nil
96	}
97	
98	// extractSkillTree walks skillName in srcFS and writes every file under
99	// destRoot, preserving the directory structure. When force is false,
100	// existing files are left alone so user edits survive re-extraction.
101	func extractSkillTree(srcFS fs.FS, skillName, destRoot string, force bool) error {
102		return fs.WalkDir(srcFS, skillName, func(path string, d fs.DirEntry, walkErr error) error {
103			if walkErr != nil {
104				return walkErr
105			}
106			rel, err := filepath.Rel(skillName, path)
107			if err != nil {
108				return err
109			}
110			// rel == "." for the skill root itself — handled by MkdirAll.
111			destPath := filepath.Join(destRoot, rel)
112			if d.IsDir() {
113				return os.MkdirAll(destPath, 0o755)
114			}
115	
116			if !force {
117				if _, err := os.Stat(destPath); err == nil {
118					// Respect user edits on re-run without --force.
119					return nil
120				}
121			}
122	
123			data, err := fs.ReadFile(srcFS, path)
124			if err != nil {
125				return fmt.Errorf("read %s: %w", path, err)
126			}
127			if err := os.MkdirAll(filepath.Dir(destPath), 0o755); err != nil {
128				return fmt.Errorf("mkdir %s: %w", filepath.Dir(destPath), err)
129			}
130			if err := os.WriteFile(destPath, data, 0o644); err != nil {
131				return fmt.Errorf("write %s: %w", destPath, err)
132			}
133			return nil
134		})
135	}
136	
137	// replaceRelativeSymlink points linkPath at target (relative). If
138	// linkPath already exists — as a real directory, a file, or another
139	// symlink — it is removed first so re-running converges on the desired
140	// target. A real directory at linkPath is an install-time data-loss
141	// risk, so it is refused explicitly rather than silently deleted.
142	func replaceRelativeSymlink(linkPath, relativeTarget string) error {
143		info, err := os.Lstat(linkPath)
144		switch {
145		case os.IsNotExist(err):
146			// Nothing to replace — fall through to create.
147		case err != nil:
148			return fmt.Errorf("inspect %s: %w", linkPath, err)
149		case info.Mode()&os.ModeSymlink != 0:
150			// Existing symlink — always replace so the target is fresh.
151			if rmErr := os.Remove(linkPath); rmErr != nil {
152				return fmt.Errorf("remove existing symlink %s: %w", linkPath, rmErr)
153			}
154		case info.IsDir():
155			// Real directory: refuse. A `.agents/skills/ddx` folder with
156			// real files is not something the global installer should wipe.
157			return fmt.Errorf("%s exists as a real directory; refusing to replace with a symlink. Remove it manually or pass --force to a future surface that handles this explicitly", linkPath)
158		default:
159			// Regular file — also unsafe to silently clobber.
160			return fmt.Errorf("%s exists as a regular file; refusing to replace", linkPath)
161		}
162		return os.Symlink(relativeTarget, linkPath)
163	}
