	// no symlinks anywhere in the install output.
	projectRoot := t.TempDir()

	// Build the plugin tree under .ddx/plugins/sample/ as if extracted there.
	pluginRoot := filepath.Join(projectRoot, ".ddx", "plugins", "sample")
	skillDir := filepath.Join(pluginRoot, ".agents", "skills", "sample-skill")
	require.NoError(t, os.MkdirAll(skillDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(skillDir, "SKILL.md"),
		[]byte("---\nname: sample-skill\ndescription: sample\n---\n"), 0o644))

	// Walk three install roots and confirm no symlinks materialized in the plugin tree.
	walkAndAssertNoSymlinks(t, pluginRoot, projectRoot)
}

